import EvaluationResponsesClient from '@/components/admin/evaluation/EvaluationResponsesClient';
import { evaluationQuestionService } from '@/services/evaluation-question-service';

export default async function EvaluationResponsesPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const data = await evaluationQuestionService.getResponses(id);

  return <EvaluationResponsesClient data={data} />;
}
